import{_ as s,C as r,o as u,c as i,E as o,j as e,a as l,ai as b}from"./chunks/framework.D76zamVX.js";const _=JSON.parse('{"title":"Дабери","description":"","frontmatter":{},"headers":[],"relativePath":"comms/anime/dub.md","filePath":"comms/anime/dub.md","lastUpdated":1748175624000}'),p={name:"comms/anime/dub.md"};function k(g,t,c,f,m,q){const a=r("Banner"),n=r("Badge");return u(),i("div",null,[o(a,{text:"Озвучення",image:"/comms/dub.png",blur:"5px"}),t[6]||(t[6]=e("h1",{id:"дабери",tabindex:"-1"},[l("Дабери "),e("a",{class:"header-anchor",href:"#дабери","aria-label":'Permalink to "Дабери"'},"​")],-1)),e("ul",null,[t[3]||(t[3]=b('<li><a href="https://t.me/AIDsubStudio" target="_blank" rel="noreferrer"><strong>AID Sub Studio</strong></a><blockquote><p>Ми молода команда, яка перекладає, та озвучує аніме українською мовою, до кожної озвученої серії робимо версію з українськими субтитрами 🇺🇦 Також ми публікуємо новини з аніме світу, та різноманітні топи.</p></blockquote></li><li><a href="https://t.me/amanogawa_ua" target="_blank" rel="noreferrer"><strong>Amanogawa</strong></a><blockquote><p>Спільнота Аманоґава – ми перекладаємо та озвучуємо аніме, збираємо інформацію та новини про аніме та Японію, висвітлюємо різноманітні анімешні та пов&#39;язані з ними події в Україні та за її межами, прагнемо просувати ліцензійну манґу та манхву і ще робимо купу-купу всього іншого, до чого можемо дотягнутися і до чого маємо натхнення.</p></blockquote></li><li><a href="https://t.me/AniUnion" target="_blank" rel="noreferrer"><strong>AniUnion</strong></a><blockquote><p>Ми команда AniUnion, займаємось озвученням та перекладом аніме та фільмів українською. Працюмо над озвученнями як старих, так і нових тайтлів.</p></blockquote></li><li><a href="https://t.me/bulbulmedia" target="_blank" rel="noreferrer"><strong>BULBUL MEDIA</strong></a><blockquote><p>Ми команда озвучення та дубляжу аніме та ін. В нашій команді проф. актори, тому продукт стараємося випускати якісний</p></blockquote></li><li><a href="https://t.me/Bambooua2022" target="_blank" rel="noreferrer"><strong>Bambooua</strong></a><blockquote><p>Ми - команда, що дарує переклади азійських фільмів/шоу/кліпів/дорам/новел українською мовою.</p></blockquote></li><li><a href="https://t.me/clan_kaizoku" target="_blank" rel="noreferrer"><strong>Clan Kaizoku</strong></a><blockquote><p>Наша команда переважно дарує озвучення для культових анімок минулого та зовсім нових тайтлів сьогодення. Також ми час від часу озвучуємо різні дорамки та не тільки.</p></blockquote></li><li><a href="https://t.me/didko_studio" target="_blank" rel="noreferrer"><strong>Didko Studio</strong></a><blockquote><p>Амбіційна студія з міста Київ, що була заснована компанією друзів. Зараз студія займається озвученням як нових тайтлів та повнометражних аніме, так і вже давно забутих, проте не менш популярних шедеврів, також в планах озвучення ігор, фільмів і т. ін.</p></blockquote></li><li><a href="https://t.me/Dzuski_com" target="_blank" rel="noreferrer"><strong>Dzuski</strong></a><blockquote><p>Незалежна озвучка Українською. Українізуємо серіали, фільми, мультфільми та аніме.</p></blockquote></li><li><a href="https://t.me/EspadaDub" target="_blank" rel="noreferrer"><strong>EspadaStudio</strong></a><blockquote><p>Ми маємо багато талановитих дабберів, які працюють над проектами озвучення для популярних аніме. Не тільки озвучуємо аніме, але й переспівуємо ваші улюблені опенінги українською на своєму YouTube каналі.</p></blockquote></li><li><a href="https://t.me/fanvoxua_re" target="_blank" rel="noreferrer"><strong>FanVoxUA</strong></a><blockquote><p>Українська некомерційна студія аматорського озвучення аніме, мультфільмів та серіалів українською мовою. Творчий доробок студії складає 250+ перекладених та озвучених українською мовою творів, найзначнішою частиною яких є аніме серіали.</p></blockquote></li><li><a href="https://t.me/flamestudioua" target="_blank" rel="noreferrer"><strong>Flame Studio</strong></a><blockquote><p>Ми молода та амбіційна команда Flame Studio. Робимо багатоголосу озвучку аніме, іноді чогось іншого, підтримуємо зв&#39;язок та відкриті до співпраці з іншими студіями, сайтами і т.д.</p></blockquote></li><li><a href="https://t.me/subfukuronachi" target="_blank" rel="noreferrer"><strong>FukuroNachi</strong></a><blockquote><p>Нова команда, яка озвучує та перекладає аніме. Заснована: 11 жовтня 2022 року. Ми молода команда яка в майбутньому планує перейти на ліцензійний дубляж аніме. Ми працюємо не на швидкість, а на якість, хоча з часом виробиться і швидкість. В Україні не так багато гарного озвучення та ми готові це скорегувати. Наразі в нашій команді 20 учасників. Кожне озвучене нами аніме наповнене емоцій. Ми стараємося робити все, щоб українське озвучення набирало обертів.</p></blockquote></li><li><a href="https://t.me/gwean_maslinka" target="_blank" rel="noreferrer"><strong>Glass Moon (Gwean &amp; Maslinka)</strong></a><blockquote><p>Ми - дует озвучувачів. Перекладаємо та озвучуємо аніме-серіали, повнометражні аніме, мультфільми українською мовою. Українізуємо як найкращі рейтингові аніме, так і новинки.</p></blockquote></li><li><a href="https://t.me/hatoshi_ua" target="_blank" rel="noreferrer"><strong>HATOSHI</strong></a><blockquote><p>Команда, яка займається озвучуванням фільмів та серіалів українською мовою.</p></blockquote></li><li><a href="https://t.me/inariDuB" target="_blank" rel="noreferrer"><strong>Inari</strong></a><blockquote><p>Ми перекладаємо й озвучуємо з 2019 року. У нашому репертуарі є такі аніме, як Вежа Бога, Клас Еліти, Бог старшої школи, Ця порцелянова лялечка закохалася, У Комі проблеми зі спілкуванням, Сходження в тіні та багато інших. Наша мета - давати глядачам якісний україномовний продукт, а також популяризувати аніме в Україні.</p></blockquote></li><li><a href="https://t.me/pan_kioto" target="_blank" rel="noreferrer"><strong>Kioto anime</strong></a><blockquote><p>Кіото аніме українською - команда перекладу та озвучення.</p></blockquote></li><li><a href="https://t.me/Kitsunestudio1" target="_blank" rel="noreferrer"><strong>Kitsune</strong></a><blockquote><p>Ми команда Kitsune. Протягом останнього року ми займались озвученням аніме, дорам і манґ українською мовою. Також ми записуємо файні кавери на опенінги, ендінги та ОСТи. У нашої команди завжди багато ідей, як хвостів у Kitsune, тому ми активно розвиваємось у різних напрямках.</p></blockquote></li><li><a href="https://t.me/lem0nkaDub" target="_blank" rel="noreferrer"><strong>Lem0nka Voice Project</strong></a><blockquote><p>Проєкт заснований акторкою озвучення та дубляжу, яка працює під псевдонімом Lem0nka. На рахунку проєкта ютуб та телеграм канали, що постійно розвиваються. Коли на ютубі ви можете подивитися найсвіжіші трейлери та добірки, в телеграмі існує основна група з новинами озвучень і бот, де систематизований увесь каталог від команди. Команда LVP не має постійного складу. Актори приходять за бажанням створити якісний продукт і йдуть, коли закінчується тайтл, аби повернутися.</p></blockquote></li><li><a href="https://t.me/lifecycledub" target="_blank" rel="noreferrer"><strong>Lifecycle</strong></a><blockquote><p>Українська фан-студія дубляжу.</p></blockquote></li><li><a href="https://t.me/melvoice" target="_blank" rel="noreferrer"><strong>Melvoice</strong></a><blockquote><p>Melvoice - це команда яка озвучує аніме українською. Melvoice - нова назва команди MelodicVoiceStudio.</p></blockquote></li><li><a href="https://t.me/quam_project" target="_blank" rel="noreferrer"><strong>QUAM Project</strong></a><blockquote><p>QuamProject – команда, що озвучує аніме, фільми, серіали та мультсеріали. Основну діяльність веде співпрацюючи з іншими командами та залучаючи самостійних перекладачів та даберів.</p></blockquote></li><li><a href="https://t.me/salo_vpalo_dub" target="_blank" rel="noreferrer"><strong>SaloVpalo</strong></a><blockquote><p>Зореліт є лідером-засновником команди. Працює в сфері українського аніме з 2011 року. Перекладав манґу, локалізував постери, керував українськими спільнотами. Серйозно несинхронним дубляжем зайнявся з 2020 року. У нинішньому складі команда сформувалася після повномасштабного вторгнення кацапів. Нині займаємося дублюванням та субтитруванням аніме. Починали ми першими з онґоїнґу Ван Піс — його ж і продовжуємо. Паралельно є й інші проекти, а також велика мета… СУБТИТРУВАННЯ ВСЬОГО СЕРІАЛУ ВАН ПІС.</p></blockquote></li><li><a href="https://t.me/+xuWWBtpCdcQzZjUy" target="_blank" rel="noreferrer"><strong>Saturn Union</strong></a><blockquote><p>Вас вітає команда Saturn Union! Ми займаємось перекладом, озвученням та дубляжем аніме, повнометражних мультфільмів та мультсеріалів солов’їною щодня. Для нас в роботі головне якість. Починаючи від підготовки перекладу, професійних навичок наших акторів і до вихідного продукту! Ми працюємо над найрізноманітнішими проєктами, будь яких жанрів та виду анімації.</p></blockquote></li><li><a href="https://t.me/Shirifugen" target="_blank" rel="noreferrer"><strong>Shirifugen</strong></a><blockquote><p>Ми займаємось цією діяльністю з вересня 2020-го року, у нашому озвученні можна побачити такі аніме як: &quot;Відчуй Вітер&quot;(спільно з UFDUB), &quot;Я поголився, а потім привів додому старшокласницю&quot;, &quot;Озума&quot;, &quot;Клуб Раймана&quot;, та інші.</p></blockquote></li><li><a href="https://t.me/Togarashidub" target="_blank" rel="noreferrer"><strong>TOGARASHI</strong></a><blockquote><p>Togarashi - команда озвучення аніме з власним стилем та &quot;перчинкою&quot;. Ми створюємо українські переклади з душею та творчим підходом. Наш головний проєкт - озвучення аніме &quot;One Piece&quot;, яке ми робимо з особливою любов&#39;ю та пристрастю. Але звісно у нас є й інші проєкти. Ми додаємо до кожного персонажа свою неповторну смакову ноту, яка робить наші переклади особливими.</p></blockquote></li><li><a href="https://t.me/TVIY_prod" target="_blank" rel="noreferrer"><strong>TVIЙ.production</strong></a><blockquote><p>ТВІЙ - це творчий колектив, що мріє назавжди змінити світ українського озвучення. Професіонали, що зібралися разом і розширюють кордони українського звуку та народжують твої улюблені історії.</p></blockquote></li><li><a href="https://t.me/prorokvoice" target="_blank" rel="noreferrer"><strong>The VOP</strong></a><blockquote><p>The VOP - це професійне та швидке озвучення. Пророк, Юджи та Дивудав, стараються звучити для вас. 💙ОЗВУЧЕННЯ ЦЕ НАШЕ ЖИТТЯ!💛</p></blockquote></li><li><a href="https://t.me/uamax_dub" target="_blank" rel="noreferrer"><strong>UAMAX</strong></a><blockquote><p>Дублювання та закадрове озвучування всього що заманеться, роблю нормально, інколи навіть краще, або гірше, як буде настрій. Співпрацюю з проф. акторами.</p></blockquote></li><li><a href="https://t.me/uaspeedfilmsdub" target="_blank" rel="noreferrer"><strong>UASPF Studio</strong></a><blockquote><p>Ми займаємося багатоголосним дубляжем, перезаписом звуку та іноді створенням озвучення для мультфільмів, фільмів, аніме та інших відео продуктів українською мовою.</p></blockquote></li><li><a href="https://t.me/UFDUB" target="_blank" rel="noreferrer"><strong>UFDUB</strong></a><blockquote><p>Команда любителів, що озвучують з душею те, що бажають глядачі й учасники проєкту!</p></blockquote></li><li><a href="https://t.me/unimay" target="_blank" rel="noreferrer"><strong>Unimay Media</strong></a><blockquote><p>Unimay Media - команда дубляжу аніме, ігрових сінематиків українською. Наша команда має досвід в дублюванні, озвученні та локалізації. Налічує в собі професіональних акторів, звукорежисерів, перекладачів. Ми надаємо комплексні послуги озвучування, включно з повноцінним постпродакшеном, керовані професіоналами.</p></blockquote></li><li><a href="https://t.me/vrdub" target="_blank" rel="noreferrer"><strong>VRDub</strong></a><blockquote><p>VRdub – команда, що озвучує різноманітні анімешки, а також, іноді, мультсеріали ти фільми. Співпрацює з іншими командами, залучає окремих діячів.</p></blockquote></li><li><a href="https://t.me/voicesband" target="_blank" rel="noreferrer"><strong>Voices Band</strong></a><blockquote></blockquote></li><li><a href="https://t.me/vmdub" target="_blank" rel="noreferrer"><strong>Ватага Мудрагеля</strong></a><blockquote></blockquote></li><li><a href="https://t.me/kisukitvdab" target="_blank" rel="noreferrer"><strong>КізукіDub</strong></a><blockquote><p>Ми - молода команда багатоголосого синхронного озвучення та дубляжу КІЗУКІ - команда, що здійснює мрії з вірою в Україну та її народ. Тільки у нас можна побачити найкращу озвучку Demon Slayer та, хай йому грець, Yarichin Club.</p></blockquote></li><li><a href="https://t.me/lisovyi_viter" target="_blank" rel="noreferrer"><strong>Лісовий Вітер</strong></a><blockquote></blockquote></li><li><a href="https://t.me/robotaholosom" target="_blank" rel="noreferrer"><strong>Робота Голосом</strong></a><blockquote><p>Команда Робота Голосом — проєкт існуючий з 2015р, який спеціалізуються на перекладі, озвученні та адаптації аніме, мультфільмів, фільмів, серіалів та брали участь в озвученні ігор українською. Українізують як класичні аніме, так і новинки.</p></blockquote></li><li><a href="https://t.me/realCossackdubbing" target="_blank" rel="noreferrer"><strong>Справжня Козацька Озвучка</strong></a><blockquote><p>СКО-команда озвучення аніме. Ми робимо і звичайну озвучку, і рофл-нарізки.</p></blockquote></li><li><a href="https://t.me/Studio_Kachur" target="_blank" rel="noreferrer"><strong>Студія Качур</strong></a><blockquote><p>Наша команда робить дубляж аніме і не тільки.</p></blockquote></li>',39)),e("li",null,[t[0]||(t[0]=e("a",{href:"https://t.me/kutochok_anime",target:"_blank",rel:"noreferrer"},[e("strong",null,"У куточку в таверні")],-1)),t[1]||(t[1]=l()),o(n,{type:"warning",text:"Припинили свою діяльність"}),t[2]||(t[2]=e("blockquote",null,[e("p",null,"Ми команда ентузіастів, яка за допомогою різних творчих засобів поширюють український контент. Це аніме, манга, підкасти, заходи тощо, бо ми не зупиняємося на одному!")],-1))]),t[4]||(t[4]=e("li",null,[e("a",{href:"https://t.me/uaspeedfilmsdub",target:"_blank",rel:"noreferrer"},[e("strong",null,"УКРОФОН")]),e("blockquote",null,[e("p",null,"УКРОФОН - це проєкт, який робить озвучення Стівена Юніверса.")])],-1)),t[5]||(t[5]=e("li",null,[e("a",{href:"https://t.me/Yuigeni",target:"_blank",rel:"noreferrer"},[e("strong",null,"Юіґень")]),e("blockquote",null,[e("p",null,"Розповсюдження україномовного контенту – це теж частина боротьби!")])],-1))])])}const d=s(p,[["render",k]]);export{_ as __pageData,d as default};
